<?php
 namespace WPAICG\ContentWriter\Ajax\Actions\GenerateTitle; use WPAICG\Core\AIPKit_OpenAI_Reasoning; if (!defined('ABSPATH')) { exit; } function prepare_ai_params_logic(array $validated_params): array { $ai_params_override = []; if (isset($validated_params['ai_temperature'])) { $ai_params_override['temperature'] = floatval($validated_params['ai_temperature']); } if (($validated_params['provider'] ?? '') === 'OpenAI') { $reasoning_effort = AIPKit_OpenAI_Reasoning::normalize_effort_for_model( (string) ($validated_params['ai_model'] ?? ''), $validated_params['reasoning_effort'] ?? '' ); if ($reasoning_effort !== '') { $ai_params_override['reasoning'] = ['effort' => $reasoning_effort]; } } elseif (($validated_params['provider'] ?? '') === 'Ollama') { $reasoning_effort = AIPKit_OpenAI_Reasoning::sanitize_effort($validated_params['reasoning_effort'] ?? ''); if ($reasoning_effort !== '' && $reasoning_effort !== 'none') { $ai_params_override['reasoning'] = ['effort' => $reasoning_effort]; } } $ai_params_override['top_p'] = null; return $ai_params_override; } 